#include <bits/stdc++.h>
using namespace std;
int main(){
    int m;
    if(!(cin >> m)) return 0;
    vector<int> arr1(m);
    for(int i = 0; i < m; i++) cin >> arr1[i];
    int n;
    cin >> n;
    vector<int> arr2(n);
    for(int i = 0; i < n; i++) cin >> arr2[i];
    set<int> unionSet;
    for(int i = 0; i < m; i++) unionSet.insert(arr1[i]);
    for(int i = 0; i < n; i++) unionSet.insert(arr2[i]);
    vector<int> unionArr(unionSet.begin(), unionSet.end());
    sort(unionArr.begin(), unionArr.end());
    for(int i = 0; i < unionArr.size(); i++) cout << unionArr[i] << ' ';
}
